using System.ComponentModel.DataAnnotations;
using Api.Models;

namespace Api.Models;

/// <summary>Response representing an order.</summary>
public sealed record OrderResponse(
    int Id,
    int CustomerId,
    DateTimeOffset PlacedAt,
    decimal TotalAmount,
    OrderStatus Status);

/// <summary>Payload for creating a new order.</summary>
public sealed record CreateOrderRequest
{
    [Required]
    public required int CustomerId { get; init; }

    [Required]
    public required DateTimeOffset PlacedAt { get; init; }

    [Required]
    [Range(0.01, double.MaxValue)]
    public required decimal TotalAmount { get; init; }

    [Required]
    public required OrderStatus Status { get; init; }
}

using Api.Models;

namespace Api.Services;

public interface IOrderService
{
    Task<IReadOnlyList<OrderResponse>> GetAllAsync(CancellationToken ct);
    Task<OrderResponse> CreateAsync(CreateOrderRequest request, CancellationToken ct);
}

using System.Collections.Concurrent;
using Api.Models;

namespace Api.Services;

public sealed class OrderService : IOrderService
{
    private readonly ConcurrentDictionary<int, OrderResponse> _orders = new();
    private int _nextId;

    public Task<IReadOnlyList<OrderResponse>> GetAllAsync(CancellationToken ct)
    {
        IReadOnlyList<OrderResponse> result = _orders.Values.ToList();
        return Task.FromResult(result);
    }

    public Task<OrderResponse> CreateAsync(CreateOrderRequest request, CancellationToken ct)
    {
        var id = Interlocked.Increment(ref _nextId);
        var order = new OrderResponse(id, request.CustomerId, request.PlacedAt, request.TotalAmount, request.Status);
        _orders[id] = order;
        return Task.FromResult(order);
    }
}

