using Api.Services;
using Microsoft.AspNetCore.Mvc;

namespace Api.Controllers;

[ApiController]
[Route("api/[controller]")]
public class OrdersController : ControllerBase
{
    private readonly IOrderService _service;

    public OrdersController(IOrderService service)
    {
        _service = service;
    }

    /// <summary>Get all orders.</summary>
    [HttpGet]
    public async Task<ActionResult<IReadOnlyList<OrderResponse>>> GetAll(CancellationToken cancellationToken)
    {
        var orders = await _service.GetAllAsync(cancellationToken);
        return Ok(orders);
    }

    /// <summary>Get an order by ID.</summary>
    [HttpGet("{id}")]
    public ActionResult<OrderResponse> GetById(int id)
    {
        // Placeholder for single-order retrieval; used by CreatedAtAction.
        return NotFound();
    }

    /// <summary>Create a new order.</summary>
    [HttpPost]
    public async Task<ActionResult<OrderResponse>> Create(
        CreateOrderRequest request, CancellationToken cancellationToken)
    {
        var order = await _service.CreateAsync(request, cancellationToken);
        return CreatedAtAction(nameof(GetById), new { id = order.Id }, order);
    }
}

